// Registro desde flujo WATI: registra al participante en Supabase
const token = $input.first().json.headers['x-wati-token'];
if (!token || token !== 'CrackTesos2026_WH_Token') {
  return [{json: {ok: 'false', mensaje: 'No autorizado'}}];
}
const body = $input.first().json.body;
let phone = (body.phone || '').toString().replace(/[^0-9]/g, '');
if (!phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
if (!phone || phone.length < 10) {
  return [{json: {ok: 'false', mensaje: 'Teléfono inválido'}}];
}
const name = (body.name || '').trim();
const termsAccepted = body.terms_accepted === true || body.terms_accepted === 'true';
return [{json: {
  ok: 'true',
  phone,
  name,
  terms_accepted: termsAccepted ? 'true' : 'false'
}}];

const row = $input.first().json;
return [{json: {
  ok: 'true',
  status: 'ok',
  action: 'registered',
  name: row.name || ''
}}];
